#include<bits/stdc++.h>
using namespace std;
const int N = 1e4+5;
long long n,mod,p[N],cnt,dp[N],ans;bool v[N];
int main(){
    cin>>n>>mod;dp[0]=1,v[0]=1,v[1]=1;
    for(int i=2;i<=n;i++){
        if(!v[i])p[++cnt]=i;
        for(int j=i*i;j<=n;j+=i)v[j]=1;
    }
    for(int i=1;i<=cnt;i++)
        for(int j=n;j>=p[i];j--){
            int now=p[i];
            while(now<=j)dp[j]=(dp[j]+(dp[j-now]*now)%mod)%mod,now*=p[i];
        }
    for(int i=0;i<=n;i++)ans=(ans+dp[i])%mod;
    cout<<ans<<"\n";
    return 0;
}
